'use client';

import {
    Anchor,
    Box,
    Button,
    Flex,
    MantineProvider,
    NativeSelect,
    Text,
    TextInput,
} from '@mantine/core';
import { useForm } from '@mantine/form';
import { notifications } from '@mantine/notifications';
import { IconAlertTriangle, IconCheck } from '@tabler/icons-react';
import { zod4Resolver } from 'mantine-form-zod-resolver';
import { useRouter } from 'next/navigation';
import ReactDOMServer from 'react-dom/server';

import { EmailInput } from '@/components/EmailInput/EmailInput';
import { config } from '@/lib/config';
import { toPublicMessage } from '@/lib/errors';
import { captureUnexpectedError } from '@/lib/observability/sentry';
import { PlayerDataType } from '@/types';
import type { CreatePlayerProxy } from '@/types/actions/CreatePlayer';
import { CreatePlayerInput, CreatePlayerSchema } from '@/types/actions/CreatePlayer';
import type { SendEmailProxy } from '@/types/actions/SendEmail';

export interface Props {
    players: PlayerDataType[];
    onCreatePlayer: CreatePlayerProxy;
    onSendEmail: SendEmailProxy;
}

/**
 * A form component for registering new players.
 *
 * Collects player information including first name, last name, email, and an optional introducer.
 * Upon submission, sends a welcome email to the new player and displays notifications for success or failure.
 *
 * @param props - Component props
 * @param props.players - Array of existing players used to populate the "Introduced by" dropdown
 *
 * @example
 * ```tsx
 * <NewPlayerForm players={existingPlayers} />
 * ```
 */
export const NewPlayerForm = ({
    players,
    onCreatePlayer,
    onSendEmail,
}: Props) => {
    const router = useRouter();
    const getPreferredEmail = (player?: PlayerDataType) => {
        if (player?.accountEmail) {
            return player.accountEmail;
        }
        if (!player?.extraEmails.length) return '';
        const verifiedEmail = player.extraEmails.find((playerEmail) => playerEmail.verifiedAt);
        return (verifiedEmail ?? player.extraEmails[0])?.email ?? '';
    };

    const form = useForm({
        initialValues: {
            name: '',
            email: '',
            introducedBy: '',
        } satisfies CreatePlayerInput,
        validate: zod4Resolver(CreatePlayerSchema),
        validateInputOnBlur: true,
    });

    const handleSubmit = async (values: CreatePlayerInput) => {
        const id = notifications.show({
            loading: true,
            title: 'Creating player',
            message: 'Creating player...',
            autoClose: false,
            withCloseButton: false,
        });

        try {
            const { player: newPlayer, inviteLink } = await onCreatePlayer(values);

            if (values.email?.length > 0) {
                const introducerEmail = values.introducedBy ?
                    getPreferredEmail(players.find((p) => p.id.toString() === values.introducedBy)) :
                    '';
                const cc = [introducerEmail, 'footy@toastboy.co.uk']
                    .filter((e): e is string => !!e).join(', ');
                const html = ReactDOMServer.renderToStaticMarkup(
                    <MantineProvider>
                        <Flex direction="column" gap="md">
                            <Text>
                                Welcome to Toastboy FC!
                            </Text>
                            <Text>
                                Follow this link to get started:
                                <Anchor href={inviteLink}>confirm your account</Anchor>
                            </Text>
                            <Text>
                                We look forward to seeing you on the pitch! The games are every Tuesday at 18:00 at Kelsey Kerridge in Cambridge. Please arrive a bit early so you&apos;ve got time to park and pay the day membership.

                                All the details are here:
                            </Text>
                            <Anchor href={`https://www.toastboy.co.uk/footy/info`}>
                                Toastboy FC info page
                            </Anchor>
                            <Text>
                                Cheers,
                                Jon
                            </Text>
                        </Flex>
                    </MantineProvider>,
                );

                await onSendEmail({
                    to: values.email,
                    cc,
                    subject: 'Welcome to Toastboy FC!',
                    html,
                });
            }

            notifications.update({
                id,
                color: 'teal',
                title: 'Player created',
                message: 'Player created successfully',
                icon: <IconCheck size={config.notificationIconSize} />,
                loading: false,
                autoClose: config.notificationAutoClose,
            });

            router.push(`/footy/player/${newPlayer.id}`);
        } catch (err) {
            captureUnexpectedError(err, {
                layer: 'client',
                component: 'NewPlayerForm',
                action: 'createPlayer',
                route: '/footy/admin/players',
                extra: {
                    email: values.email,
                    introducedBy: values.introducedBy,
                },
            });
            notifications.update({
                id,
                color: 'red',
                title: 'Error',
                message: toPublicMessage(
                    err,
                    err instanceof Error ? String(err) : 'Failed to create player.',
                ),
                icon: <IconAlertTriangle size={config.notificationIconSize} />,
                loading: false,
                autoClose: false,
                withCloseButton: true,
            });
        }
    };

    const introducers = [
        { label: '(Nobody)', value: '' },
        ...players.map((player) => ({
            label: player.name ?? '',
            value: player.id.toString(),
        })).sort((a, b) => a.label.localeCompare(b.label)),
    ];

    return (
        <Box
            maw={400}
            component="form"
            onSubmit={form.onSubmit(handleSubmit)}
        >
            <TextInput
                label="Name"
                required
                {...form.getInputProps('name')}
            />
            <EmailInput
                label="Email address"
                description="If no email is provided, the player will not be able to log in but the profile will still be created."
                {...form.getInputProps('email')}
            />
            <NativeSelect
                label="Introduced by"
                data={introducers}
                {...form.getInputProps('introducedBy')}
            />

            <Button type="submit" mt="md">
                Add player
            </Button>
        </Box>
    );
};

import 'server-only';

import type { SendMailOptions } from 'nodemailer';

import { sendEmailCore } from '@/lib/actions/sendEmail';
import playerService from '@/services/Player';
import type { SendEmailProxy } from '@/types/actions/SendEmail';
import type {
    SendEmailToAllActivePlayersResult,
} from '@/types/actions/SendEmailToAllActivePlayers';

interface SendEmailToAllActivePlayersDeps {
    playerService: Pick<typeof playerService, 'getAll'>;
    sendEmail: SendEmailProxy;
}

const defaultDeps: SendEmailToAllActivePlayersDeps = {
    playerService,
    sendEmail: sendEmailCore,
};

/**
 * Normalises an email address by trimming whitespace and converting to lower case.
 *
 * Accepts `string`, `null`, or `undefined` and returns an empty string when the
 * input is not provided. This helper does not validate that the result is a
 * syntactically valid email address.
 *
 * @param email - The email address to normalise.
 * @returns The normalised email address, or an empty string when not provided.
 */
function normalizeEmail(email: string) {
    return email.trim().toLowerCase();
}

/**
 * Sends one email to all active players with de-duplicated recipients.
 *
 * Active players are those without a `finished` timestamp.
 * Recipients are built from account and extra email addresses.
 *
 * @param data - Email content payload.
 * @param deps - Optional service and email dependencies.
 * @returns The number of unique recipients emailed.
 */
export async function sendEmailToAllActivePlayersCore(
    mailOptions: Omit<SendMailOptions, 'bcc'>,
    deps: SendEmailToAllActivePlayersDeps = defaultDeps,
): Promise<SendEmailToAllActivePlayersResult> {
    const players = await deps.playerService.getAll({ activeOnly: true });

    const recipients = new Set<string>();
    for (const player of players) {
        if (player.accountEmail) {
            const normalizedEmail = normalizeEmail(player.accountEmail);
            recipients.add(normalizedEmail);
        }

        for (const extraEmail of player.extraEmails) {
            if (extraEmail.verifiedAt) {
                const normalizedEmail = normalizeEmail(extraEmail.email);
                recipients.add(normalizedEmail);
            }
        }
    }

    if (recipients.size === 0) {
        return { recipientCount: 0 };
    }

    const sortedRecipients = Array.from(recipients).sort();
    await deps.sendEmail({
        ...mailOptions,
        bcc: sortedRecipients.join(','),
    });
    return { recipientCount: recipients.size };
}

