/**
 * Get a single player's email contact data by id.
 * @param id The numeric ID for the player
 * @returns A promise that resolves to the player's email data, or null if not found
 */
async getEmailDataById(id: number): Promise<PlayerEmailDataDisplayType | null> {
    const where = PlayerWhereUniqueInputObjectSchema.parse({ id });
    const player = await prisma.player.findUnique({
        where,
        select: {
            id: true,
            name: true,
            anonymous: true,
            accountEmail: true,
            extraEmails: {
                orderBy: [
                    { verifiedAt: 'desc' },
                    { createdAt: 'desc' },
                ],
            },
        },
    });
    if (!player) return null;

    const { extraEmails, ...rest } = player;
    return {
        ...this.sanitizePlayerName(rest),
        extraEmails: extraEmails.map(({ email, verifiedAt }) => ({ email, verified: verifiedAt != null })),
    };
}

